import React from "react";
import {
  BookOpenIcon,
  ClipboardDocumentListIcon,
  ChartBarIcon,
  AcademicCapIcon,
  StarIcon,
} from "@heroicons/react/24/solid";

export default function UserDashboard() {
  return (
    <div className="min-h-screen bg-gray-100 p-6">

      {/* Header */}
      <h1 className="text-3xl font-bold mb-6">My Dashboard</h1>

      {/* Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">

        <DashboardCard
          title="My Resources"
          icon={<BookOpenIcon className="h-10 w-10 text-indigo-500" />}
        />

        <DashboardCard
          title="My Tasks"
          icon={<ClipboardDocumentListIcon className="h-10 w-10 text-green-500" />}
        />

        <DashboardCard
          title="Progress"
          icon={<ChartBarIcon className="h-10 w-10 text-purple-500" />}
        />

        <DashboardCard
          title="Quizzes"
          icon={<AcademicCapIcon className="h-10 w-10 text-pink-500" />}
        />

        <DashboardCard
          title="My Ratings"
          icon={<StarIcon className="h-10 w-10 text-yellow-500" />}
        />

      </div>
    </div>
  );
}

// Reusable Dashboard Card
function DashboardCard({ title, icon }) {
  return (
    <div className="bg-white p-6 rounded-2xl shadow hover:shadow-lg transition cursor-pointer">
      {icon}
      <h2 className="mt-4 text-xl font-semibold">{title}</h2>
    </div>
  );
}
